mapper.select:
SELECT b.img_disp_type, b.os_type, b.img_size, b.img_url FROM tb_rcmmd_similar_track a JOIN tb_rcmmd_img_mang b ON a.disp_sn = b.disp_sn AND a.rcmmd_similar_track_id = #{recommendId} AND b.rcmmd_type_id = #{recommendType} /* only RC_SML_TR */
AND b.img_disp_type = #{imageType}
AND b.os_type = #{osType}
JOIN ( SELECT CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AS dfk_type UNION SELECT 'EVERY' ) c ON b.dfk_type = c.dfk_type ORDER BY a.disp_sn

SELECT b.img_disp_type, b.os_type, b.img_size, b.img_url
FROM tb_rcmmd_prefer_genre_similar_track a JOIN tb_map_img_rcmmd_img b ON a.svc_genre_id = b.img_content_id AND a.rcmmd_prefer_genre_similar_track_id = #{recommendId}
FROM tb_rcmmd_mforu a JOIN tb_map_img_rcmmd_img b ON a.svc_genre_id = b.img_content_id AND a.rcmmd_mforu_id = #{recommendId}
AND b.img_content_type = 'GENRE' AND b.rcmmd_type_id = #{recommendType}
AND b.os_type = #{osType}
AND b.img_disp_type = #{imageType}
JOIN ( SELECT CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AS dfk_type UNION SELECT 'EVERY' ) c ON b.dfk_type = c.dfk_type ORDER BY a.disp_sn

SELECT c.img_url FROM
tb_rcmmd_img_mang c WHERE c.dfk_type = CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AND c.disp_sn = #{dispSn} AND c.rcmmd_type_id = 'RC_SML_TR' AND c.img_disp_type = 'MAIN_TOP' AND c.os_type = #{osType} ORDER BY c.disp_sn LIMIT 1
tb_rcmmd_prefer_genre_similar_track a INNER JOIN tb_svc_genre b ON a.svc_genre_id = b.svc_genre_id LEFT OUTER JOIN tb_map_img_rcmmd_img c ON b.svc_genre_id = c.img_content_id AND c.img_content_type = 'GENRE' AND c.rcmmd_type_id = 'RC_GR_TR' AND c.os_type = #{osType} AND c.dfk_type = CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AND c.img_disp_type = 'MAIN_TOP' WHERE a.rcmmd_prefer_genre_similar_track_id = #{rcmmdId}
LIMIT 1
tb_rcmmd_mforu a INNER JOIN tb_svc_genre b ON a.svc_genre_id = b.svc_genre_id LEFT OUTER JOIN tb_map_img_rcmmd_img c ON b.svc_genre_id = c.img_content_id AND c.rcmmd_type_id = 'RC_CF_TR' AND c.os_type = #{osType} AND c.img_disp_type = 'MAIN_TOP' AND c.img_content_type = 'GENRE' AND c.disp_sn = #{dispSn}
WHERE rcmmd_mforu_id = #{rcmmdId}
